-- Stays 서비스 DB 초기화 (솔데스크 실제 데이터 기반)
-- VM3 PostgreSQL 16
SET client_encoding = 'UTF8';
SET standard_conforming_strings = on;

CREATE TABLE public.amenities (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    name character varying(100) NOT NULL
);

CREATE TABLE public.bookings (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    user_id uuid,
    stay_id uuid,
    room_id uuid,
    check_in date NOT NULL,
    check_out date NOT NULL,
    guests integer NOT NULL,
    total_price integer NOT NULL,
    status character varying(20) DEFAULT 'confirmed'::character varying,
    created_at timestamp without time zone DEFAULT now(),
    event_id uuid,
    original_price integer,
    cleaning_fee integer DEFAULT 30000,
    service_fee integer DEFAULT 0,
    payment_method character varying(50),
    special_request text,
    coupon_id uuid
);

CREATE TABLE public.coupons (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    code character varying(20) NOT NULL,
    event_id uuid,
    stay_id uuid,
    discount_rate integer,
    total_count integer,
    remaining_count integer,
    used_by uuid,
    is_used boolean DEFAULT false,
    created_at timestamp without time zone DEFAULT now()
);

CREATE TABLE public.event_stays (
    event_id uuid NOT NULL,
    stay_id uuid NOT NULL,
    discount_rate integer DEFAULT 0,
    remaining_rooms integer DEFAULT 10
);

CREATE TABLE public.events (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    title character varying(255) NOT NULL,
    description text,
    discount_rate integer,
    start_date date,
    end_date date,
    status character varying(20) DEFAULT 'upcoming'::character varying,
    type character varying(50),
    region character varying(100),
    total_rooms integer DEFAULT 500,
    remaining_rooms integer DEFAULT 500,
    banner_color character varying(20) DEFAULT '#111111'::character varying
);

CREATE TABLE public.reviews (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    user_id uuid,
    stay_id uuid,
    booking_id uuid,
    rating integer,
    content text,
    created_at timestamp without time zone DEFAULT now(),
    CONSTRAINT reviews_rating_check CHECK (((rating >= 1) AND (rating <= 5)))
);

CREATE TABLE public.rooms (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    stay_id uuid,
    name character varying(100) NOT NULL,
    max_guests integer NOT NULL,
    price_per_night integer NOT NULL,
    room_count integer DEFAULT 1,
    remaining_count integer DEFAULT 1
);

CREATE TABLE public.stay_amenities (
    stay_id uuid NOT NULL,
    amenity_id uuid NOT NULL
);

CREATE TABLE public.stay_images (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    stay_id uuid,
    url character varying(500) NOT NULL,
    is_main boolean DEFAULT false
);

CREATE TABLE public.stays (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    name character varying(255) NOT NULL,
    description text,
    region character varying(100) NOT NULL,
    address character varying(255),
    lat double precision,
    lng double precision,
    price_per_night integer NOT NULL,
    max_guests integer NOT NULL,
    rating double precision DEFAULT 0,
    review_count integer DEFAULT 0,
    host_id uuid,
    created_at timestamp without time zone DEFAULT now()
);

CREATE TABLE public.users (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    email character varying(255) NOT NULL,
    password character varying(255) NOT NULL,
    name character varying(100) NOT NULL,
    phone character varying(20),
    created_at timestamp without time zone DEFAULT now()
);












ALTER TABLE ONLY public.amenities ADD CONSTRAINT amenities_pkey PRIMARY KEY (id);
ALTER TABLE ONLY public.bookings ADD CONSTRAINT bookings_pkey PRIMARY KEY (id);
ALTER TABLE ONLY public.coupons ADD CONSTRAINT coupons_pkey PRIMARY KEY (id);
ALTER TABLE ONLY public.event_stays ADD CONSTRAINT event_stays_pkey PRIMARY KEY (event_id, stay_id);
ALTER TABLE ONLY public.events ADD CONSTRAINT events_pkey PRIMARY KEY (id);
ALTER TABLE ONLY public.reviews ADD CONSTRAINT reviews_pkey PRIMARY KEY (id);
ALTER TABLE ONLY public.rooms ADD CONSTRAINT rooms_pkey PRIMARY KEY (id);
ALTER TABLE ONLY public.stay_amenities ADD CONSTRAINT stay_amenities_pkey PRIMARY KEY (stay_id, amenity_id);
ALTER TABLE ONLY public.stay_images ADD CONSTRAINT stay_images_pkey PRIMARY KEY (id);
ALTER TABLE ONLY public.stays ADD CONSTRAINT stays_pkey PRIMARY KEY (id);
ALTER TABLE ONLY public.users ADD CONSTRAINT users_email_key UNIQUE (email);
ALTER TABLE ONLY public.users ADD CONSTRAINT users_pkey PRIMARY KEY (id);

ALTER TABLE ONLY public.bookings ADD CONSTRAINT bookings_coupon_id_fkey FOREIGN KEY (coupon_id) REFERENCES public.coupons(id);
ALTER TABLE ONLY public.bookings ADD CONSTRAINT bookings_event_id_fkey FOREIGN KEY (event_id) REFERENCES public.events(id);
ALTER TABLE ONLY public.bookings ADD CONSTRAINT bookings_room_id_fkey FOREIGN KEY (room_id) REFERENCES public.rooms(id);
ALTER TABLE ONLY public.bookings ADD CONSTRAINT bookings_stay_id_fkey FOREIGN KEY (stay_id) REFERENCES public.stays(id);
ALTER TABLE ONLY public.bookings ADD CONSTRAINT bookings_user_id_fkey FOREIGN KEY (user_id) REFERENCES public.users(id);
ALTER TABLE ONLY public.coupons ADD CONSTRAINT coupons_event_id_fkey FOREIGN KEY (event_id) REFERENCES public.events(id);
ALTER TABLE ONLY public.coupons ADD CONSTRAINT coupons_used_by_fkey FOREIGN KEY (used_by) REFERENCES public.users(id);
ALTER TABLE ONLY public.event_stays ADD CONSTRAINT event_stays_event_id_fkey FOREIGN KEY (event_id) REFERENCES public.events(id) ON DELETE CASCADE;
ALTER TABLE ONLY public.event_stays ADD CONSTRAINT event_stays_stay_id_fkey FOREIGN KEY (stay_id) REFERENCES public.stays(id) ON DELETE CASCADE;
ALTER TABLE ONLY public.reviews ADD CONSTRAINT reviews_stay_id_fkey FOREIGN KEY (stay_id) REFERENCES public.stays(id);
ALTER TABLE ONLY public.reviews ADD CONSTRAINT reviews_user_id_fkey FOREIGN KEY (user_id) REFERENCES public.users(id);
ALTER TABLE ONLY public.rooms ADD CONSTRAINT rooms_stay_id_fkey FOREIGN KEY (stay_id) REFERENCES public.stays(id) ON DELETE CASCADE;
ALTER TABLE ONLY public.stay_images ADD CONSTRAINT stay_images_stay_id_fkey FOREIGN KEY (stay_id) REFERENCES public.stays(id) ON DELETE CASCADE;
ALTER TABLE ONLY public.stays ADD CONSTRAINT stays_host_id_fkey FOREIGN KEY (host_id) REFERENCES public.users(id);
